const checkpoints = [];

const artworks = JSON.parse(localStorage.getItem('artworks') || '[]');
const favoritesLists = JSON.parse(localStorage.getItem('favorites') || '[]');
const favoriteItems = JSON.parse(localStorage.getItem('favorite_items') || '[]');

// Compute target artworks dynamically: landscapes, year >= 2022, price <= 300, sorted by price asc
const qualifyingArtworks = artworks
  .filter(a => a && a.category === 'landscape' && typeof a.year === 'number' && a.year >= 2022 && typeof a.price === 'number' && a.price <= 300)
  .sort((a, b) => {
    const pa = typeof a.price === 'number' ? a.price : Number.POSITIVE_INFINITY;
    const pb = typeof b.price === 'number' ? b.price : Number.POSITIVE_INFINITY;
    if (pa !== pb) return pa - pb;
    return (a.year || 0) - (b.year || 0);
  });

const targetArtworks = qualifyingArtworks.slice(0, 2);
const targetIds = targetArtworks.map(a => a.id);

let qualifyingFavoriteCount = 0;
if (favoritesLists.length && targetIds.length) {
  const listId = favoritesLists[0].id;
  const favoriteArtworkIds = favoriteItems
    .filter(fi => fi && fi.favorites_list_id === listId && fi.artwork_id)
    .map(fi => fi.artwork_id);

  qualifyingFavoriteCount = targetIds.filter(id => favoriteArtworkIds.includes(id)).length;
}

// CP1 (0.5): At least one of the correct target artworks is in favorites
checkpoints.push({ passed: qualifyingFavoriteCount >= 1, weight: 0.5 });

// CP2 (0.5): Both of the correct target artworks are in favorites
checkpoints.push({ passed: qualifyingFavoriteCount >= 2, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

// All cityscape prints
const cityscapePrints = products.filter(p => p && p.shop_category === 'prints' && p.category === 'cityscape' && p.status === 'active');

let mostRecentYear = null;
cityscapePrints.forEach(p => {
  if (typeof p.year === 'number') {
    if (mostRecentYear === null || p.year > mostRecentYear) mostRecentYear = p.year;
  }
});

const mostRecentPrints = (mostRecentYear === null)
  ? []
  : cityscapePrints.filter(p => p.year === mostRecentYear);

// Helper to get largest size label for a product
function getLargestSizeLabel(prod) {
  const opts = Array.isArray(prod.size_options) ? prod.size_options : [];
  if (!opts.length) return prod.default_size_label || null;
  let best = null;
  let bestArea = -1;
  opts.forEach(o => {
    const w = typeof o.width_cm === 'number' ? o.width_cm : 0;
    const h = typeof o.height_cm === 'number' ? o.height_cm : 0;
    const area = w * h;
    if (area > bestArea) {
      bestArea = area;
      best = o;
    }
  });
  return best ? best.label : (prod.default_size_label || null);
}

// Helper to get black frame label for a product
function getBlackFrameLabel(prod) {
  const opts = Array.isArray(prod.frame_options) ? prod.frame_options : [];
  let label = null;
  opts.forEach(o => {
    if (!o || !o.label) return;
    if (o.code === 'black_frame' || /black\s*frame/i.test(o.label)) {
      label = o.label;
    }
  });
  return label;
}

// Cart items that are cityscape prints
const cartCityscapePrintItems = cartItems.filter(ci => {
  const prod = products.find(p => p && p.id === ci.product_id);
  return prod && prod.shop_category === 'prints' && prod.category === 'cityscape';
});

// CP1 (0.3): User has at least one cart item that is a cityscape print
checkpoints.push({ passed: cartCityscapePrintItems.length > 0, weight: 0.3 });

// Among cityscape print cart items, find those for the most recent year
const cartMostRecentItems = cartCityscapePrintItems.filter(ci => {
  const prod = products.find(p => p && p.id === ci.product_id);
  return prod && mostRecentYear !== null && prod.year === mostRecentYear;
});

// CP2 (0.3): User has at least one cart item for a cityscape print from the most recent year
checkpoints.push({ passed: cartMostRecentItems.length > 0, weight: 0.3 });

// CP3 (0.2): For at least one most-recent cityscape print in cart, the selected size is the largest available
let hasLargestSize = false;
for (const ci of cartMostRecentItems) {
  const prod = products.find(p => p && p.id === ci.product_id);
  if (!prod) continue;
  const largestLabel = getLargestSizeLabel(prod);
  if (largestLabel && ci.selected_size_label === largestLabel) {
    hasLargestSize = true;
    break;
  }
}
checkpoints.push({ passed: hasLargestSize, weight: 0.2 });

// CP4 (0.2): For at least one most-recent cityscape print in cart, quantity is 1 and frame is black
let hasBlackFrameQty1 = false;
for (const ci of cartMostRecentItems) {
  const prod = products.find(p => p && p.id === ci.product_id);
  if (!prod) continue;
  const blackLabel = getBlackFrameLabel(prod);
  if (blackLabel && ci.selected_frame_label === blackLabel && ci.quantity === 1) {
    hasBlackFrameQty1 = true;
    break;
  }
}
checkpoints.push({ passed: hasBlackFrameQty1, weight: 0.2 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const artworks = JSON.parse(localStorage.getItem('artworks') || '[]');
const wishlists = JSON.parse(localStorage.getItem('wishlists') || '[]');
const wishlistItems = JSON.parse(localStorage.getItem('wishlist_items') || '[]');

// Find qualifying pastel artworks under 200 and width <= 50 cm, sorted by size (area) ascending
const qualifying = artworks
  .filter(a => a && a.color_palette === 'pastel' && typeof a.price === 'number' && a.price <= 200 && typeof a.width_cm === 'number' && a.width_cm <= 50)
  .sort((a, b) => {
    const areaA = (a.width_cm || 0) * (a.height_cm || 0);
    const areaB = (b.width_cm || 0) * (b.height_cm || 0);
    return areaA - areaB;
  });

const targetArtworks = qualifying.slice(0, 3);
const targetIds = targetArtworks.map(a => a.id);

let qualifyingWishlistCount = 0;
if (wishlists.length && targetIds.length) {
  const listId = wishlists[0].id;
  const wishlistArtworkIds = wishlistItems
    .filter(wi => wi && wi.wishlist_id === listId && wi.artwork_id)
    .map(wi => wi.artwork_id);

  qualifyingWishlistCount = targetIds.filter(id => wishlistArtworkIds.includes(id)).length;
}

// CP1 (0.33): At least one of the correct target artworks is in the wishlist
checkpoints.push({ passed: qualifyingWishlistCount >= 1, weight: 0.33 });

// CP2 (0.33): At least two of the correct target artworks are in the wishlist
checkpoints.push({ passed: qualifyingWishlistCount >= 2, weight: 0.33 });

// CP3 (0.34): All three of the correct target artworks are in the wishlist
checkpoints.push({ passed: qualifyingWishlistCount >= 3, weight: 0.34 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const requests = JSON.parse(localStorage.getItem('commission_requests') || '[]');

function isAround600(budget) {
  return typeof budget === 'number' && budget >= 500 && budget <= 700;
}

function isSeptember2025(dateStr) {
  if (!dateStr) return false;
  const d = new Date(dateStr);
  if (isNaN(d.getTime())) return false;
  const year = d.getUTCFullYear();
  const month = d.getUTCMonth(); // 0-based, 8 = September
  return year === 2025 && month === 8;
}

// CP1 (0.25): At least one request for artwork_type 'portrait'
const portraitRequests = requests.filter(r => r && r.artwork_type === 'portrait');
checkpoints.push({ passed: portraitRequests.length > 0, weight: 0.25 });

// CP2 (0.25): At least one request for a portrait with medium 'acrylic_on_canvas'
const acrylicPortraits = portraitRequests.filter(r => r.medium === 'acrylic_on_canvas');
checkpoints.push({ passed: acrylicPortraits.length > 0, weight: 0.25 });

// CP3 (0.25): At least one portrait acrylic request with budget around 600
const acrylicPortraitsBudget = acrylicPortraits.filter(r => isAround600(r.budget));
checkpoints.push({ passed: acrylicPortraitsBudget.length > 0, weight: 0.25 });

// CP4 (0.25): At least one portrait acrylic request with budget around 600 and preferred completion date in September 2025
const fullyQualifying = acrylicPortraitsBudget.filter(r => isSeptember2025(r.preferred_completion_date));
checkpoints.push({ passed: fullyQualifying.length > 0, weight: 0.25 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const exhibitions = JSON.parse(localStorage.getItem('exhibitions') || '[]');
const visitPlans = JSON.parse(localStorage.getItem('visit_plans') || '[]');
const visitPlanItems = JSON.parse(localStorage.getItem('visit_plan_items') || '[]');

const fromDate = new Date('2025-07-01T00:00:00Z');

// All exhibitions starting on/after 2025-07-01
const qualifyingExh = exhibitions.filter(e => {
  if (!e || !e.start_date) return false;
  const d = new Date(e.start_date);
  if (isNaN(d.getTime())) return false;
  return d >= fromDate;
});

qualifyingExh.sort((a, b) => {
  const da = new Date(a.start_date);
  const db = new Date(b.start_date);
  return da - db;
});

const earliest = qualifyingExh[0] || null;
const qualifyingIds = new Set(qualifyingExh.map(e => e.id));

let anyQualifyingInPlan = false;
let earliestInPlan = false;

if (visitPlans.length && visitPlanItems.length) {
  const planId = visitPlans[0].id;
  const itemsForPlan = visitPlanItems.filter(vi => vi && vi.visit_plan_id === planId);
  const exIdsInPlan = itemsForPlan.map(vi => vi.exhibition_id);

  anyQualifyingInPlan = exIdsInPlan.some(id => qualifyingIds.has(id));
  if (earliest) {
    earliestInPlan = exIdsInPlan.includes(earliest.id);
  }
}

// CP1 (0.4): At least one exhibition starting on/after 2025-07-01 is in the visit plan
checkpoints.push({ passed: anyQualifyingInPlan, weight: 0.4 });

// CP2 (0.6): The earliest such exhibition is in the visit plan
checkpoints.push({ passed: earliestInPlan, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const projects = JSON.parse(localStorage.getItem('projects') || '[]');
const inquiries = JSON.parse(localStorage.getItem('collaboration_inquiries') || '[]');

// All 2023 mural projects for business/commercial clients
const bizMural2023 = projects.filter(p => p && p.client_type === 'business_commercial' && p.project_category === 'mural' && p.year === 2023);
const firstBizMural2023 = bizMural2023[0] || null;

const bizMural2023Ids = new Set(bizMural2023.map(p => p.id));
const bizMural2023Titles = new Set(bizMural2023.map(p => p.title));

function referencesProject(inquiry, idsSet, titlesSet) {
  if (!inquiry) return false;
  if (inquiry.project_reference_id && idsSet.has(inquiry.project_reference_id)) return true;
  if (inquiry.project_reference_title && titlesSet.has(inquiry.project_reference_title)) return true;
  return false;
}

// CP1 (0.3): At least one inquiry references any 2023 business mural project
const anyBizMuralInquiry = inquiries.some(i => referencesProject(i, bizMural2023Ids, bizMural2023Titles));
checkpoints.push({ passed: anyBizMuralInquiry, weight: 0.3 });

// CP2 (0.3): At least one inquiry specifically references the first such project
let firstProjectReferenced = false;
let inquiryForFirst = null;
if (firstBizMural2023) {
  for (const i of inquiries) {
    const idMatch = i.project_reference_id === firstBizMural2023.id;
    const titleMatch = i.project_reference_title === firstBizMural2023.title;
    if (idMatch || titleMatch) {
      firstProjectReferenced = true;
      inquiryForFirst = i;
      break;
    }
  }
}
checkpoints.push({ passed: firstProjectReferenced, weight: 0.3 });

// CP3 (0.4): That inquiry's message mentions a café mural and 4m x 2.5m dimensions
let cafeAndSizeMentioned = false;
if (inquiryForFirst && typeof inquiryForFirst.message === 'string') {
  const msg = inquiryForFirst.message.toLowerCase();
  const hasCafe = msg.includes('cafe') || msg.includes('caf9');
  const has4m = msg.includes('4m');
  const has2_5m = msg.includes('2.5m') || msg.includes('2,5m');
  cafeAndSizeMentioned = hasCafe && has4m && has2_5m;
}
checkpoints.push({ passed: cafeAndSizeMentioned, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const subs = JSON.parse(localStorage.getItem('newsletter_subscriptions') || '[]');
const interestRows = JSON.parse(localStorage.getItem('newsletter_subscription_interests') || '[]');
const documents = JSON.parse(localStorage.getItem('documents') || '[]');

// Determine latest active lookbook year
const activeLookbooks = documents.filter(d => d && d.document_category === 'lookbook' && d.file_type === 'pdf' && d.status === 'active');
let latestLookbookYear = null;
activeLookbooks.forEach(d => {
  if (typeof d.year === 'number') {
    if (latestLookbookYear === null || d.year > latestLookbookYear) latestLookbookYear = d.year;
  }
});

function getInterestsForSub(subId) {
  return interestRows
    .filter(r => r && r.subscription_id === subId)
    .map(r => r.interest_code);
}

// Subscriptions that are monthly and have both required interests
const qualifyingSubs = subs.filter(s => {
  if (!s || s.frequency !== 'monthly_summary') return false;
  const codes = new Set(getInterestsForSub(s.id));
  return codes.has('new_prints_shop_updates') && codes.has('exhibitions_events');
});

// CP1 (0.5): At least one subscription with monthly summary and both interests (new prints + exhibitions)
checkpoints.push({ passed: qualifyingSubs.length > 0, weight: 0.5 });

// CP2 (0.5): At least one such subscription has downloaded the latest active lookbook (year 2024 in this data)
let downloadedLatest = false;
if (latestLookbookYear !== null) {
  downloadedLatest = qualifyingSubs.some(s => {
    if (latestLookbookYear === 2024) {
      return s.lookbook_2024_downloaded === true;
    }
    // For other years, extend if needed in future
    return false;
  });
}
checkpoints.push({ passed: downloadedLatest, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const products = JSON.parse(localStorage.getItem('products') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

// Originals under $1000, preserving storage order
const originalsUnder = products.filter(p => p && p.shop_category === 'originals' && typeof p.price === 'number' && p.price <= 1000 && p.status === 'active');

const firstTwo = originalsUnder.slice(0, 2);
let targetProductId = null;
if (firstTwo.length === 1) {
  targetProductId = firstTwo[0].id;
} else if (firstTwo.length === 2) {
  const h1 = typeof firstTwo[0].height_cm === 'number' ? firstTwo[0].height_cm : 0;
  const h2 = typeof firstTwo[1].height_cm === 'number' ? firstTwo[1].height_cm : 0;
  if (h2 > h1) {
    targetProductId = firstTwo[1].id;
  } else {
    targetProductId = firstTwo[0].id;
  }
}

// CP1 (0.3): At least one cart item is an original product priced under $1000
const cartOriginalsUnder = cartItems.filter(ci => {
  const prod = products.find(p => p && p.id === ci.product_id);
  return prod && prod.shop_category === 'originals' && typeof prod.price === 'number' && prod.price <= 1000;
});
checkpoints.push({ passed: cartOriginalsUnder.length > 0, weight: 0.3 });

// CP2 (0.3): At least one cart item is for the taller of the first two qualifying originals (any quantity > 0)
const hasTargetInCart = targetProductId ? cartItems.some(ci => ci.product_id === targetProductId && (ci.quantity || 0) > 0) : false;
checkpoints.push({ passed: hasTargetInCart, weight: 0.3 });

// CP3 (0.4): At least one cart item is for that target product with quantity exactly 1
const hasTargetQty1 = targetProductId ? cartItems.some(ci => ci.product_id === targetProductId && ci.quantity === 1) : false;
checkpoints.push({ passed: hasTargetQty1, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
